.settings-sidebar {
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    min-width: 220px;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.sidebar-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    color: #495057;
    font-size: 0.95rem;
    transition: background-color 0.15s, color 0.15s, border-left 0.15s;
    border-left: 3px solid transparent;
    user-select: none;
}

.sidebar-item:hover {
    background: #e9ecef;
    color: #212529;
}

.sidebar-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.15rem;
    width: 1.5rem;
    text-align: center;
}

