                               checked="@channel.Muted"
                               @onchange="e => channel.Muted = (bool)e.Value!" />
                        <label class="form-check-label" for="@($"ch-{channel.Name}")">
                            #@channel.Name
                        </label>
                    </div>
                </div>
            }
        </div>

        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Preferences")
            </button>
