{"file_text": "@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security</h3>
    <p class="section-description">Manage your password, two-factor authentication, and sessions</p>

    @if (_loading)
    {
        <div class="text-muted p-4">Loading security settings…</div>
    }
    else
    {
        <ChangePasswordPanel OnPasswordChange="HandlePasswordChangeAsync" />

        <div class="tfa-section mt-4">
            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Two-Factor Authentication</div>
                    <div class="toggle-hint">
                        @if (_twoFactorEnabled)
                        {
                            <span class="status-badge enabled">● Enabled</span>
                        }
                        else
                        {
                            <span class="status-badge disabled">● Disabled</span>
                        }
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)e.Value!" />
                </div>
            </div>

            @if (_lastPasswordChange.HasValue)
            {
                <p class="text-muted mt-2" style="font-size:0.85rem;">
                    Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <h5 class="mt-4 mb-3">Active Sessions</h5>
        <div class="sessions-table-container">
            <table class="table table-hover sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td class="text-end">
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <RevokeSessionDialog Visible="_revokeTarget is not null"
                             Session="_revokeTarget"
                             OnConfirm="ConfirmRevokeAsync"
                             OnCancel="() => _revokeTarget = null" />
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string _currentSessionId = "";
    private ActiveSession? _revokeTarget;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        // Treat the first session as the current one for demo purposes
        _currentSessionId = _sessions.FirstOrDefault()?.Id ?? "";
        _loading = false;
    }

    private async Task HandlePasswordChangeAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private void PromptRevoke(ActiveSession session)
    {
        _revokeTarget = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_revokeTarget is null) return;
        await SettingsService.RevokeSessionAsync(_revokeTarget.Id);
        _sessions.RemoveAll(s => s.Id == _revokeTarget.Id);
        _revokeTarget = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
