@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Profile</h3>
    <p class="section-description">Manage your personal information</p>

    @if (_loading)
    {
        <div class="text-muted p-4">Loading profile…</div>
    }
    else
    {
        <div class="avatar-area">
            <div class="avatar-preview">
                @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                {
                    <img src="@_avatarUrl" alt="Avatar" />
                }
                else
                {
                    <span class="avatar-placeholder">👤</span>
                }
            </div>
            <div class="avatar-url-field">
                <label class="form-label">Avatar URL</label>
                <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="4" @bind="_bio"></textarea>
        </div>

        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
                Discard Changes
            </button>
        </div>

        @if (_toast is not null)
        {
            <div class="alert alert-success toast-message">@_toast</div>
        }
    }
</div>

@code {
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _loading = true;
    private bool _saving;
    private string? _toast;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toast = null;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _saving = false;
        _toast = "Profile saved successfully!";
        _ = DismissToastAsync();
    }

    private void Discard()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
        _toast = null;
    }

    private async Task DismissToastAsync()
    {
        await Task.Delay(3000);
        _toast = null;
        await InvokeAsync(StateHasChanged);
    }
}

