toolArgs.file_text:
.settings-section {
    padding: 2rem;
    max-width: 640px;
}

.settings-section h3 {
    margin: 0 0 0.25rem;
    font-weight: 600;
}

.section-description {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.25rem;
    margin-bottom: 1.5rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    flex-shrink: 0;
    border: 2px solid #dee2e6;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2rem;
}

.avatar-url-field {
    flex: 1;
    min-width: 0;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 1rem;
}

.toast-message {
    margin-top: 1rem;
    animation: fadeInUp 0.3s ease;
}

@keyframes fadeInUp {
    from { opacity: 0; transform: translateY(8px); }
    to   { opacity: 1; transform: translateY(0); }
}

