toolArgs.file_text:
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Notifications</h3>
    <p class="section-description">Choose how and when you want to be notified</p>

    @if (_loading)
    {
        <div class="text-muted p-4">Loading preferences…</div>
    }
    else
    {
        <div class="toggle-group">
            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Email Notifications</div>
                    <div class="toggle-hint">Receive notifications via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)e.Value!" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Push Notifications</div>
                    <div class="toggle-hint">Receive push notifications in your browser</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)e.Value!" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Weekly Digest</div>
                    <div class="toggle-hint">Get a summary of activity each week</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)e.Value!" />
                </div>
            </div>
        </div>

        <h5 class="mt-4 mb-3">Muted Channels</h5>
        <div class="channel-list">
            @foreach (var channel in _channels)
            {
                <div class="channel-item">
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                               checked="@channel.Muted"
                               @onchange="e => channel.Muted = (bool)e.Value!" />
                        <label class="form-check-label" for="@($"ch-{channel.Name}")">
                            #@channel.Name
                        </label>
                    </div>
                </div>
            }
        </div>

        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Preferences")
            </button>
        </div>

        @if (_toast is not null)
        {
            <div class="alert alert-success toast-message">@_toast</div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelModel> _channels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _toast;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _channels = prefs.MutedChannels
            .Select(c => new ChannelModel { Name = c, Muted = true })
            .ToList();
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toast = null;
        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _toast = "Notification preferences saved!";
        _ = DismissToastAsync();
    }

    private async Task DismissToastAsync()
    {
        await Task.Delay(3000);
        _toast = null;
        await InvokeAsync(StateHasChanged);
    }

    private class ChannelModel
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }
}

