@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="section-description">Customize how the application looks and feels</p>

    @if (_loading)
    {
        <div class="text-muted p-4">Loading appearance settings…</div>
    }
    else
    {
        <div class="option-group">
            <h6>Theme</h6>
            <div class="radio-group">
                @foreach (var theme in _themes)
                {
                    <label class="radio-card @(_theme == theme ? "selected" : "")">
                        <input type="radio" name="theme" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <span>@theme</span>
                    </label>
                }
            </div>
        </div>

        <div class="option-group">
            <h6>Font Size</h6>
            <div class="radio-group">
                @foreach (var size in _fontSizes)
                {
                    <label class="radio-card @(_fontSize == size ? "selected" : "")">
                        <input type="radio" name="fontSize" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <span>@size</span>
                    </label>
                }
            </div>
        </div>

        <div class="option-group">
            <h6>Language</h6>
            <select class="form-select" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <div class="option-group">
            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Compact Mode</div>
                    <div class="toggle-hint">Reduce spacing and padding throughout the UI</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)e.Value!" />
                </div>
            </div>
        </div>

        <h5 class="mt-4 mb-3">Preview</h5>
        <div class="preview-area @GetPreviewClasses()">
            <div class="preview-header">Sample Header</div>
            <p class="preview-text">
                This is how your content will look with the selected appearance settings.
                The quick brown fox jumps over the lazy dog.
            </p>
            <div class="preview-actions">
                <button class="btn btn-sm btn-primary">Primary</button>
                <button class="btn btn-sm btn-outline-secondary">Secondary</button>
            </div>
        </div>

        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        @if (_toast is not null)
        {
            <div class="alert alert-success toast-message">@_toast</div>
        }
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _toast;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add($"preview-font-{_fontSize.ToLowerInvariant()}");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toast = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        _toast = "Appearance settings saved!";
        _ = DismissToastAsync();
    }

    private async Task DismissToastAsync()
    {
        await Task.Delay(3000);
        _toast = null;
        await InvokeAsync(StateHasChanged);
    }
}

