toolArgs.file_text:
.settings-section {
    padding: 2rem;
    max-width: 640px;
}

.settings-section h3 {
    margin: 0 0 0.25rem;
    font-weight: 600;
}

.section-description {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

.option-group {
    margin-bottom: 1.5rem;
}

.option-group h6 {
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.radio-group {
    display: flex;
    gap: 0.5rem;
}

.radio-card {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.5rem 1rem;
    border: 2px solid #dee2e6;
    border-radius: 0.5rem;
    cursor: pointer;
    font-size: 0.9rem;
    transition: border-color 0.15s, background-color 0.15s;
    user-select: none;
}

.radio-card:hover {
    border-color: #adb5bd;
}

.radio-card.selected {
    border-color: #0d6efd;
    background: #e7f1ff;
}

.radio-card input[type="radio"] {
    accent-color: #0d6efd;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.toggle-label {
    font-weight: 500;
}

.toggle-hint {
    font-size: 0.85rem;
    color: #6c757d;
}

/* Live preview area */
.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 0.75rem;
    padding: 1.5rem;
    transition: all 0.25s ease;
}

.preview-header {
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.preview-text {
    margin-bottom: 0.75rem;
}

.preview-actions {
    display: flex;
    gap: 0.5rem;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
    border-color: #dee2e6;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-system {
    background: #f0f0f5;
    color: #2d2d3a;
    border-color: #c5c5d0;
}

/* Font size variants */
.preview-font-small {
    font-size: 0.825rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.15rem;
}

/* Compact mode */
.preview-compact {
    padding: 0.75rem;
    line-height: 1.3;
}

.preview-compact .preview-header {
    margin-bottom: 0.25rem;
}

.preview-compact .preview-text {
    margin-bottom: 0.35rem;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 1.25rem;
}

.toast-message {
    margin-top: 1rem;
    animation: fadeInUp 0.3s ease;
}

@keyframes fadeInUp {
    from { opacity: 0; transform: translateY(8px); }
    to   { opacity: 1; transform: translateY(0); }
}

