@if (Visible)
{
    <div class="dialog-backdrop" @onclick="Cancel">
        <div class="dialog-panel" @onclick:stopPropagation="true">
            <h5 class="dialog-title">Revoke Session</h5>
            <p>
                Are you sure you want to revoke the session on
                <strong>@Session?.Device</strong> from <strong>@Session?.Location</strong>?
            </p>
            <p class="text-muted">This will sign out that device immediately.</p>
            <div class="dialog-actions">
                <button class="btn btn-outline-secondary" @onclick="Cancel">Cancel</button>
                <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

